/* Particles.js - Basic particle animation library */
!function(window){window.particlesJS=function(tag_id,options){var canvas_el=document.getElementById(tag_id);if(!canvas_el){console.error('particles.js: canvas element not found');return;}var canvas=canvas_el,ctx=canvas.getContext('2d'),particles=[],particlesIndex=0,options=options||{};canvas.width=window.innerWidth;canvas.height=window.innerHeight;var defaults={number:{value:80},color:{value:'#667eea'},shape:{type:'circle'},opacity:{value:0.5},size:{value:3},move:{speed:2,direction:'none',random:true}};options=Object.assign(defaults,options);function createParticle(){var x=Math.random()*canvas.width,y=Math.random()*canvas.height;return{x:x,y:y,vx:(Math.random()-0.5)*options.move.speed,vy:(Math.random()-0.5)*options.move.speed,radius:options.size.value,color:options.color.value,opacity:options.opacity.value};}function drawParticle(particle){ctx.beginPath();ctx.arc(particle.x,particle.y,particle.radius,0,Math.PI*2);ctx.fillStyle='rgba('+hexToRgb(particle.color).r+','+hexToRgb(particle.color).g+','+hexToRgb(particle.color).b+','+particle.opacity+')';ctx.fill();}function hexToRgb(hex){var result=/^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);return result?{r:parseInt(result[1],16),g:parseInt(result[2],16),b:parseInt(result[3],16)}:{r:0,g:0,b:0};}function update(){ctx.clearRect(0,0,canvas.width,canvas.height);for(var i=0;i<particles.length;i++){var p=particles[i];p.x+=p.vx;p.y+=p.vy;if(p.x<0||p.x>canvas.width)p.vx=-p.vx;if(p.y<0||p.y>canvas.height)p.vy=-p.vy;drawParticle(p);}}function animate(){update();requestAnimationFrame(animate);}for(var i=0;i<options.number.value;i++){particles.push(createParticle());}animate();window.addEventListener('resize',function(){canvas.width=window.innerWidth;canvas.height=window.innerHeight;});};if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',function(){if(document.getElementById('particles-js')){particlesJS('particles-js',{number:{value:80,density:{enable:true,value_area:800}},color:{value:'#667eea'},shape:{type:'circle',stroke:{width:0,color:'#000000'},polygon:{nb_sides:5},image:{src:'img/github.svg',width:100,height:100}},opacity:{value:0.5,random:false,anim:{enable:false,speed:1,opacity_min:0.1,sync:false}},size:{value:3,random:true,anim:{enable:false,speed:40,size_min:0.1,sync:false}},line_linked:{enable:true,distance:150,color:'#667eea',opacity:0.4,width:1},move:{enable:true,speed:2,direction:'none',random:false,straight:false,out_mode:'out',bounce:false,attract:{enable:false,rotateX:600,rotateY:1200}}});}});}else{if(document.getElementById('particles-js')){particlesJS('particles-js',{number:{value:80,density:{enable:true,value_area:800}},color:{value:'#667eea'},shape:{type:'circle',stroke:{width:0,color:'#000000'},polygon:{nb_sides:5},image:{src:'img/github.svg',width:100,height:100}},opacity:{value:0.5,random:false,anim:{enable:false,speed:1,opacity_min:0.1,sync:false}},size:{value:3,random:true,anim:{enable:false,speed:40,size_min:0.1,sync:false}},line_linked:{enable:true,distance:150,color:'#667eea',opacity:0.4,width:1},move:{enable:true,speed:2,direction:'none',random:false,straight:false,out_mode:'out',bounce:false,attract:{enable:false,rotateX:600,rotateY:1200}}});}};}(window);
